// UTC calculations to match stored entry dates
const ONE_DAY_MS = 24 * 60 * 60 * 1000;
const nowMs = Date.now();

// Calculate today at midnight UTC
const todayMidnightUTC = Math.floor(nowMs / ONE_DAY_MS) * ONE_DAY_MS;

const thresholdDays = 16;
const cutoffMidnightUTC = todayMidnightUTC - (thresholdDays * ONE_DAY_MS);

const allItems = $input.all();

// Flatten all opportunities from all pages
const allOpportunities = allItems.flatMap(item => 
  item.json?.opportunities || []
);

// Filter for eligible opportunities
const eligible = allOpportunities.filter(opp => {
  const entryField = opp.customFields?.find(f => f.id === "YOUR_ENTRY_DATE_FIELD_ID");
  if (!entryField?.fieldValueDate) return false;

  // Entry date is stored as midnight UTC
  const entryMidnightUTC = entryField.fieldValueDate;

  // Keep if entry date is at or before cutoff (both UTC)
  return entryMidnightUTC <= cutoffMidnightUTC;
});

console.log(`Processed ${allItems.length} pages with ${allOpportunities.length} total opportunities`);
console.log(`Found ${eligible.length} opportunities ready to move to Active Nurture`);

return eligible.map(opp => ({ json: opp }));

